// دالة تشغيل السورة مع دعم الشيخ المتغير ودعم ميزة الإشعارات في الخلفية
async function playSurah(id, name) {
    const playerBar = document.getElementById('audio-player-bar');
    const nameDisplay = document.getElementById('current-surah-name');
    const playPauseBtn = document.getElementById('play-pause-btn');
    
    // هنا السحر: بيسحب السيرفر بتاع الشيخ المختار حالياً ويضيف عليه رقم السورة
    audio.src = `${currentReciterServer}${id}.mp3`;
    
    try {
        await audio.play();
        if (playerBar) playerBar.style.display = 'flex';
        // إظهار اسم السورة واسم الشيخ اللي بيقرأ
        if (nameDisplay) nameDisplay.innerText = `سورة ${name} (بصوت ${currentReciterName})`;
        if (playPauseBtn) playPauseBtn.innerText = "⏸";

        // --- كود ميزة التحكم والتشغيل من إشعارات التليفون ---
        if ('mediaSession' in navigator) {
            // البحث عن كائن الشيخ الحالي لجلب اسم الصورة المخصصة له
            const currentReciterObj = recitersData.find(r => r.name === currentReciterName);
            // تحويل مسار الصورة المحلي إلى رابط كامل ومطلق لكي يتعرف عليه نظام أندرويد/iOS في الإشعار
            const absoluteImgUrl = new URL(currentReciterObj.img, window.location.href).href;

            navigator.mediaSession.metadata = new MediaMetadata({
                title: `سورة ${name}`,
                artist: currentReciterName,
                album: "القرآن الكريم المطور",
                artwork: [
                    { src: absoluteImgUrl, sizes: '96x96',   type: 'image/jpeg' },
                    { src: absoluteImgUrl, sizes: '128x128', type: 'image/jpeg' },
                    { src: absoluteImgUrl, sizes: '192x192', type: 'image/jpeg' },
                    { src: absoluteImgUrl, sizes: '256x256', type: 'image/jpeg' },
                    { src: absoluteImgUrl, sizes: '384x384', type: 'image/jpeg' },
                    { src: absoluteImgUrl, sizes: '512x512', type: 'image/jpeg' }
                ]
            });

            // التحكم في زر التشغيل من داخل الإشعار
            navigator.mediaSession.setActionHandler('play', () => {
                audio.play();
                if (playPauseBtn) playPauseBtn.innerText = "⏸";
            });

            // التحكم في زر الإيقاف المؤقت من داخل الإشعار
            navigator.mediaSession.setActionHandler('pause', () => {
                audio.pause();
                if (playPauseBtn) playPauseBtn.innerText = "▶";
            });
        }
    } catch (e) { 
        alert("تأكد من اتصالك بالإنترنت، أو أن السيرفر يعمل."); 
    }
}





