function updateClock() {
    const clockElement = document.getElementById('current-time'); 
    if (clockElement) {
        const now = new Date();
        // استخدام الإعدادات المحلية لتحويل الوقت لنظام 12 ساعة تلقائياً
        clockElement.innerText = now.toLocaleTimeString('ar-EG', { 
            hour: '2-digit', 
            minute: '2-digit', 
            second: '2-digit', 
            hour12: true // هذا السطر هو المسؤول عن نظام الـ 12 ساعة
        });
    }
}


// دالة مساعدة لتحويل الوقت من 24 لـ 12 ساعة (ضعيها هنا)
function formatTo12Hr(timeStr) {
    if(!timeStr) return "";
    let [hours, minutes] = timeStr.split(':');
    hours = parseInt(hours);
    let period = hours >= 12 ? "م" : "ص";
    hours = hours % 12 || 12; 
    return `${hours}:${minutes} ${period}`;
}

// دالة جلب المواقيت المعدلة
async function fetchPrayers() {
    try {
        const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Zagazig&country=Egypt&method=5');
        const json = await res.json();
        const times = json.data.timings;
        
        const prayerIds = { Fajr: 'fajr', Dhuhr: 'dhuhr', Asr: 'asr', Maghrib: 'maghrib', Isha: 'isha' };
        
        for (let key in prayerIds) {
            let el = document.getElementById(prayerIds[key]);
            if (el) {
                // هنا بنادي دالة التحويل عشان يظهر "3:27 م" بدل "15:27"
                el.innerText = formatTo12Hr(times[key]);
            }
        }
        calculateNextPrayer(times);
    } catch (e) { 
        console.log("خطأ في جلب المواقيت: " + e); 
    }
}


function calculateNextPrayer(timings) {
    const now = new Date();
    const prayerOrder = [
        { name: "الفجر", time: timings.Fajr },
        { name: "الظهر", time: timings.Dhuhr },
        { name: "العصر", time: timings.Asr },
        { name: "المغرب", time: timings.Maghrib },
        { name: "العشاء", time: timings.Isha }
    ];
    for (let prayer of prayerOrder) {
        let pTime = new Date();
        let [hrs, mins] = prayer.time.split(':');
        pTime.setHours(hrs, mins, 0);
        if (pTime > now) {
            let diff = pTime - now;
            let h = Math.floor(diff / 3600000);
            let m = Math.floor((diff % 3600000) / 60000);
            const timerEl = document.getElementById('next-prayer-timer');
            if (timerEl) timerEl.innerText = `باقي على ${prayer.name} ${h} س و ${m} د`;
            return;
        }
    }
}

