function decrementCount(element) {
    let current = parseInt(element.innerText);
    if (current > 0) {
        current--;
        element.innerText = current === 0 ? "✓" : current;
        if (current === 0) {
            element.style.background = "rgba(116, 241, 217, 0.6)";
            element.style.color = "#000";
        }
        if (navigator.vibrate) navigator.vibrate(40);
    }
}

