function openTasks() {
    hideAllSections();
    document.getElementById('tasks-container').style.display = 'block';
    document.getElementById('back-btn').style.display = 'block';
    renderTasks();
}

function addTask() {
    const input = document.getElementById('task-input');
    if (!input || !input.value.trim()) return;
    myTasks.push({ id: Date.now(), text: input.value, completed: false });
    saveTasks();
    input.value = "";
}

function toggleTask(id) {
    myTasks = myTasks.map(t => t.id === id ? {...t, completed: !t.completed} : t);
    saveTasks();
}

function deleteTask(id) {
    myTasks = myTasks.filter(t => t.id !== id);
    saveTasks();
}

function saveTasks() {
    localStorage.setItem('myAppTasks', JSON.stringify(myTasks));
    renderTasks();
}

function renderTasks() {
    const list = document.getElementById('tasks-list');
    if (!list) return;

    list.innerHTML = myTasks.map(t => `
        <div class="task-item ${t.completed ? 'completed' : ''}">
            <div style="display:flex; align-items:center; gap:10px;">
                <div class="task-checkbox ${t.completed ? 'checked' : ''}" 
                     onclick="toggleTask(${t.id})">
                </div>
                
                <span class="task-text" style="font-size:${currentFontSize}px;">
                    ${t.text}
                </span>
            </div>
            
            <button class="delete-task" onclick="deleteTask(${t.id})">×</button>
        </div>`).join('');
}

