function changeFontSize(action) {
    if (action === 'increase' && currentFontSize < 50) currentFontSize += 2;
    if (action === 'decrease' && currentFontSize > 16) currentFontSize -= 2;
    applyFontSize();
    localStorage.setItem('userFontSize', currentFontSize);
}

