function setActive(element, section) {
    // 1. مسح الحالة النشطة من أزرار القائمة السفلية
    
    document.getElementById('back-btn').style.display = 'none';
  
    document.querySelectorAll('.nav-item').forEach(item => {
        item.classList.remove('active');
    });
    
    if (element) element.classList.add('active');

    // 2. قائمة بجميع الأقسام (تم إضافة useful-content-section هنا)
    const allPages = [
        'main-prayer-ui',      // الرئيسية
        'hadith-section',      // قائمة الأحاديث
        'hadith-display-page', // صفحة الحديث المنفرد
        'azkar-list-container', // الأذكار
        'quran-list-section',   // القرآن
        'tasks-container',      // المهام
        'mosques-section',     // المساجد
        'sebha-container',      // السبحة
        'useful-content-section' // القسم الجديد للمحتوى النافع
    ];

    // إخفاء كل شيء قبل البدء
    allPages.forEach(id => {
        const page = document.getElementById(id);
        if (page) page.style.display = 'none';
    });

    // 3. تحديد القسم المطلوب بدقة
    let targetId = '';
    if (section === 'main') targetId = 'main-prayer-ui';
    else if (section === 'quran') targetId = 'quran-list-section';
    else if (section === 'hadith') targetId = 'hadith-section';
    else if (section === 'tasks') targetId = 'tasks-container';
    else if (section === 'mosques') targetId = 'mosques-section'; 
    else if (section === 'sebha') targetId = 'sebha-container';
    else if (section === 'azkar') targetId = 'azkar-list-container';
    else if (section === 'useful-content') targetId = 'useful-content-section'; // الربط الجديد للزرار بالقسم

    const targetPage = document.getElementById(targetId);

    if (targetPage) {
        targetPage.style.display = 'block';
        
        // تشغيل الدوال الفرعية بناءً على القسم
        if (section === 'main') {
            document.getElementById('main-prayer-ui').style.display = 'block';
        }
        if (section === 'quran') {
            if (typeof openQuranList === "function") openQuranList();
        }
        if (section === 'tasks') {
            if (typeof openTasks === "function") openTasks();
        }
        if (section === 'hadith') {
            if (typeof openHadith === "function") openHadith();
        }
        if (section === 'mosques') {
            document.getElementById('back-btn').style.display = 'block';
        }
        // إظهار زر الرجوع عند فتح المحتوى النافع
        if (section === 'useful-content') {
            document.getElementById('back-btn').style.display = 'block';
        }
    } else {
        console.error("القسم غير موجود في الـ HTML: " + targetId);
    }

    // 4. شريط الصوت (للبرنامج)
    const audioBar = document.getElementById('audio-player-bar');
    const mainAudio = document.getElementById('main-audio');
    if (section === 'quran' && mainAudio && mainAudio.src !== "") {
        if (audioBar) audioBar.style.display = 'flex';
    } else {
        if (audioBar) audioBar.style.display = 'none';
    }

    window.scrollTo(0, 0);
}





