function showCategories() {
    // 1. إخفاء صفحة عرض الحديث المنفرد (تأكدي من الاسم ده)
    const displayPage = document.getElementById('hadith-display-page');
    if (displayPage) displayPage.style.display = 'none';

    // 2. إخفاء سكشن الأحاديث بالكامل والشبكة بتاعته
    const hadithSection = document.getElementById('hadith-section');
    if (hadithSection) {
        hadithSection.style.display = 'none';
        // نرجع شكل الشبكة لوضعها الطبيعي عشان لما نفتحها تاني تبان صح
        const menuGrid = hadithSection.querySelector('.categories-grid');
        if (menuGrid) menuGrid.style.display = 'grid';
    }

    // 3. إخفاء كل السكاشن التانية (أذكار، قرآن، مهام) عشان الضمان
    document.querySelectorAll('.section').forEach(s => s.style.display = 'none');
    document.querySelectorAll('.smooth-entry').forEach(s => s.style.display = 'none');

    // 4. إظهار الشاشة الرئيسية وزرار القائمة
    document.getElementById('main-prayer-ui').style.display = 'block';
    
    // 5. إخفاء زر الرجوع بما إننا في الرئيسية
    const backBtn = document.getElementById('back-btn');
    if (backBtn) backBtn.style.display = 'none';

    // رجوع لأول الصفحة
    window.scrollTo(0, 0);
}


// استبدلي كل دوال showHadith اللي عندك بالنسخة دي بس
function showHadith(category) {
    let data = hadithData[category]; 
    
    // العناصر بناءً على الـ HTML بتاعك
    const section = document.getElementById('hadith-section'); // القائمة الرئيسية
    const displayPage = document.getElementById('hadith-display-page'); // الصفحة اللي فيها الحديث
    const textElement = document.getElementById('hadith-text');
    const sourceElement = document.getElementById('hadith-source');
    const nextBtn = document.getElementById('next-hadith-btn');
    const backBtn = document.getElementById('back-btn'); // زرار الرجوع العلوي

    if (data && section && displayPage) {
        if (!Array.isArray(data)) data = [data];

        // --- نظام منع التكرار (زي ما هو) ---
        if (!hadithHistory[category]) hadithHistory[category] = [];
        let availableIndexes = data.map((_, i) => i).filter(i => !hadithHistory[category].includes(i));

        if (availableIndexes.length === 0) {
            hadithHistory[category] = [];
            availableIndexes = data.map((_, i) => i);
        }

        const randomIndex = availableIndexes[Math.floor(Math.random() * availableIndexes.length)];
        hadithHistory[category].push(randomIndex);
        let selected = data[randomIndex];

        // --- التحكم في الظهور (التوافق الحقيقي) ---
        section.style.display = 'none';      // إخفاء شبكة الأزرار
        displayPage.style.display = 'block'; // إظهار صفحة الحديث
        
        // إخفاء زرار الرجوع الأزرق (العلوي) عشان نستخدم الزرار الأحمر اللي في الصفحة
        if (backBtn) backBtn.style.display = 'none';

        // وضع النص
        if (textElement) textElement.innerText = `«${selected.text}»`;
        if (sourceElement) sourceElement.innerText = selected.source || "";

        // تشغيل زرار "حديث آخر"
        if (nextBtn) {
            nextBtn.onclick = () => showHadith(category);
        }
        
        window.scrollTo(0, 0);
    }
}

