// 1. رابط صوت بديل ومضمون (تكة خفيفة)
// 1. رابط صوت بديل ومضمون (تكة خفيفة)
// استبدلي الرابط اللي بين القوسين بالرابط اللي عج
// 1. تعريف الصوت (اخترت لكِ صوت هادئ ومناسب للأزرار)
// 1. رابط صوت سريع جداً ومباشر
// دالة لتوليد صوت "تكة" احترافية برمجياً بدون ملفات خارجية
// 1. تجهيز محرك الصوت مرة واحدة فقط عند البداية
const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

function playTick() {
    // لو المحرك في وضع السكون (بسبب قوانين المتصفح) بنخليه يصحى
    if (audioCtx.state === 'suspended') {
        audioCtx.resume();
    }

    const oscillator = audioCtx.createOscillator();
    const gain = audioCtx.createGain();

    oscillator.type = 'sine'; 
    oscillator.frequency.setValueAtTime(1200, audioCtx.currentTime); // تردد أعلى شوية عشان يكون أوضح
    
    gain.gain.setValueAtTime(0.1, audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.05); // وقت أقصر (0.05) عشان السرعة

    oscillator.connect(gain);
    gain.connect(audioCtx.destination);

    oscillator.start();
    oscillator.stop(audioCtx.currentTime + 0.05);
}

// 2. ربط سريع جداً مع الأزرار
document.addEventListener('mousedown', (e) => { // استخدمنا mousedown بدل click لأنها أسرع في الاستجابة
    if (e.target.closest('button') || e.target.closest('.card') || e.target.closest('.surah-card')) {
        playTick();
    }
});  

function changeAppFont(fontClass) {
    // مصفوفة بكل كلاسات الخطوط اللي ضفناها في الـ CSS
    const allFonts = [
        'font-cairo', 'font-tajawal', 'font-amiri', 'font-kufi', 
        'font-almarai', 'font-messiri', 'font-changa', 'font-ruqaa',
        'font-lalezar', 'font-kufam', 'font-lemonada', 'font-mirza',
        'font-scheherazade', 'font-vibes', 'font-harmattan'
    ];
    
    // مسح أي كلاس خط موجود حالياً على الـ body
    document.body.classList.remove(...allFonts);
    
    // إضافة الكلاس الجديد
    document.body.classList.add(fontClass);
    
    // حفظ في ذاكرة المتصفح
    localStorage.setItem('userFont', fontClass);
}
// كود تشغيل الخط المحفوظ تلقائياً عند فتح التطبيق
document.addEventListener('DOMContentLoaded', () => {
    // 1. هنجيب الخط اللي المستخدم اختاره قبل كدة من ذاكرة المتصفح
    const savedFont = localStorage.getItem('userFont');
    
    // 2. لو لقينا خط محفوظ، هنطبقه فوراً
    if (savedFont) {
        // بنمسح أي خطوط تانية عشان ميتلخبطوش
        const allFonts = [
            'font-cairo', 'font-tajawal', 'font-amiri', 'font-kufi', 
            'font-almarai', 'font-messiri', 'font-changa', 'font-ruqaa',
            'font-lalezar', 'font-kufam', 'font-lemonada', 'font-mirza',
            'font-scheherazade', 'font-vibes', 'font-harmattan'
        ];
        document.body.classList.remove(...allFonts);
        
        // بنضيف الخط المحفوظ
        document.body.classList.add(savedFont);
        
        // 3. بنخلي القائمة (Select) تظهر الخط اللي شغال فعلاً
        const fontSelector = document.getElementById('font-selector');
        if (fontSelector) {
            fontSelector.value = savedFont;
        }
    }
});

