async function getUserLocation() {
    const listContainer = document.getElementById('mosques-list');
    
    listContainer.innerHTML = `
        <div style="text-align:center; color:white; padding:20px;">
            <div class="loader" style="margin:auto;"></div>
            <p style="margin-top:15px;">جاري جلب قائمة المساجد القريبة منك...</p>
        </div>`;

    if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(async (position) => {
            const { latitude: lat, longitude: lon } = position.coords;
            
            // هنستخدم رابط بحث جوجل المباشر كـ "مصدر بيانات" سريع وموثوق
            // ده هيجيب لك مساجد حقيقية في منطقتك (زقازيق، القاهرة، أي مكان)
            const searchQuery = `مساجد`;
            const searchUrl = `https://www.google.com/maps/search/${searchQuery}/@${lat},${lon},15z`;

            // بما إننا عايزين "قائمة" داخل التطبيق، هنعمل محاكاة ذكية للقائمة 
            // بتوجه المستخدم لأدق نتائج ممكنة
            listContainer.innerHTML = `
                <h3 style="color:#74F1D9; text-align:right; margin-bottom:15px;">🕋 مساجد في موقعك الحالي:</h3>
                
                <div onclick="window.open('${searchUrl}', '_blank')" 
                     style="cursor:pointer; background:rgba(255,255,255,0.1); padding:20px; border-radius:15px; border:2px solid #74F1D9; margin-bottom:15px; text-align:center;">
                    <b style="color:white; font-size:18px; display:block;">فتح القائمة التفاعلية بالأسماء</b>
                    <p style="font-size:13px; color:#74F1D9; margin-top:10px;">📍 اضغطي هنا لعرض أقرب 10 مساجد بالأسماء والمسافات فوراً على الخريطة</p>
                </div>

                <p style="color:#eee; font-size:12px; text-align:center; opacity:0.8;">
                    (تم تحديد موقعك بدقة، اضغطي بالأعلى لرؤية النتائج الحية)
                </p>
            `;
            
        }, () => {
            listContainer.innerHTML = '<p style="color:red; text-align:center;">يجب السماح بالوصول للموقع لتظهر المساجد.</p>';
        }, { enableHighAccuracy: true, timeout: 5000 });
    }
}





// البحث عن كل بطاقات الفيديوهات في تطبيق أذكار المسلم
// ننتظر حتى يتم تحميل الصفحة بالكامل
// دالة الترتيب العشوائي
// دالة الشقلبة الذكية
// دالة لترتيب الفيديوهات عشوائياً مرة واحدة وبدون تهنيج
document.addEventListener('DOMContentLoaded', () => {
    const videoCards = document.querySelectorAll('.hadith-card');
    let favorites = JSON.parse(localStorage.getItem('myFavVideos')) || [];

    videoCards.forEach((card) => {
        // 1. استخدام رابط الفيديو (iframe src) كبصمة فريدة بدل الـ Index
        const iframe = card.querySelector('iframe');
        if (!iframe) return; // لو مفيش فيديو في الكارت ميعملش حاجة
        
        const videoURL = iframe.src; 

        // 2. إضافة زر المفضلة
        const favBtn = document.createElement('div');
        favBtn.className = 'favorite-btn';
        favBtn.innerHTML = '<i class="ri-heart-line"></i>';
        
        // التأكد من حالة القلب من الذاكرة بناءً على الرابط
        if (favorites.includes(videoURL)) {
            favBtn.classList.add('active');
            favBtn.querySelector('i').classList.replace('ri-heart-line', 'ri-heart-fill');
        }

        card.style.position = 'relative';
        card.appendChild(favBtn);

        // 3. برمجة الضغط
        favBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            favBtn.classList.toggle('active');
            const icon = favBtn.querySelector('i');

            if (favBtn.classList.contains('active')) {
                icon.classList.replace('ri-heart-line', 'ri-heart-fill');
                if (!favorites.includes(videoURL)) favorites.push(videoURL);
            } else {
                icon.classList.replace('ri-heart-fill', 'ri-heart-line');
                favorites = favorites.filter(url => url !== videoURL);
            }
            localStorage.setItem('myFavVideos', JSON.stringify(favorites));
        });
    });
});




async function fetchAccurateHijri() {
    try {
        // بنطلب التاريخ الهجري بناءً على تاريخ اليوم من سيرفر خارجي دقيق
        const response = await fetch('https://api.aladhan.com/v1/gToH?date=' + new Date().toLocaleDateString('en-GB').replace(/\//g, '-'));
        const data = await response.json();
        
        if (data.code === 200) {
            const hijri = data.data.hijri;
            const day = hijri.day;
            const month = hijri.month.ar; // اسم الشهر بالعربي (رمضان، شوال..)
            const year = hijri.year;
            
            // تحويل الأرقام لشكل عربي
            const arabicDay = new Intl.NumberFormat('ar-EG').format(day);
            const arabicYear = new Intl.NumberFormat('ar-EG').format(year);

            document.getElementById('hijri-text').textContent = `${arabicDay} ${month} ${arabicYear} هـ`;
        }
    } catch (error) {
        console.log("النت مقفول، هنرجع للحسابات اليدوية مؤقتاً");
        getTrueHijri(); // دالة الحسابات الرياضية اللي عملناها كاحتياطي
    }
}

