function openAsmaa() {
    const list = document.getElementById('asmaaList');
    
    if (list) {
        list.innerHTML = ''; 
        
        asmaaData.forEach(item => {
            const itemDiv = document.createElement('div');
            itemDiv.style.cssText = "background: rgba(255,255,255,0.1); padding: 15px; border-radius: 15px; border: 1px solid rgba(255,255,255,0.1); cursor: pointer; transition: 0.3s;";
            
            // التعديل هنا: بدلاً من alert نستخدم وظيفة عرض المودال
            itemDiv.onclick = () => showDescription(item.name, item.detail);
            
            itemDiv.innerHTML = `
                <h3 style="margin: 0; color: #FFD700; font-size: 18px;">${item.name}</h3>
                <small style="font-size: 10px; color: #ddd;">اضغط للشرح</small>
            `;
            list.appendChild(itemDiv);
        });
        
        document.getElementById('asmaaModal').style.display = 'block';
    }
}

// وظيفة جديدة لعرض الشرح داخل النافذة الشيك
function showDescription(name, detail) {
    const modal = document.getElementById('descriptionModal');
    document.getElementById('modalTitle').innerText = name;
    document.getElementById('modalBody').innerText = detail;
    modal.style.display = 'flex';
}

// وظيفة إغلاق نافذة الشرح
function closeDescModal() {
    document.getElementById('descriptionModal').style.display = 'none';
}

function closeAsmaa() {
    document.getElementById('asmaaModal').style.display = 'none';
}
    
    
    
    
    
    
