window.addEventListener('load', () => {
    updateDisplay();
});

// 3. دالة التحديث (تدعم الـ IDs المكررة لضمان الأداء)
function updateDisplay() {
    const displays = document.querySelectorAll('#counter-display');
    displays.forEach(display => {
        display.innerText = rosaryCount;
    });
}

// 4. فتح السبحة (توسيط كامل وإخفاء العناصر الأخرى)
function openRosary() {
    // إخفاء كل شيء (الرئيسية، البطاقات، الحاويات)
    document.querySelectorAll('.section, .main-card, .grid-container, .menu-container').forEach(s => {
        s.style.display = 'none';
    });
    
    const rosarySection = document.getElementById('rosary-section');
    if (rosarySection) {
        rosarySection.style.display = 'flex'; // استخدام flex للتوسيط المعتمد في الـ CSS
    }

    const backBtn = document.getElementById('back-btn');
    if (backBtn) backBtn.style.display = 'block';
}

// 5. العودة للرئيسية (تنظيف الشاشة)
function showMainSection() {
    // إخفاء السبحة وزر الرجوع
    const rosarySection = document.getElementById('rosary-section');
    if (rosarySection) rosarySection.style.display = 'none';

    const backBtn = document.getElementById('back-btn');
    if (backBtn) backBtn.style.display = 'none';

    // إظهار عناصر الصفحة الرئيسية
    document.querySelectorAll('.section, .main-card, .grid-container').forEach(element => {
        // نستخدم block أو flex حسب تصميمك الأصلي للرئيسية
        element.style.display = 'block'; 
    });
}

// 6. دالة زيادة العداد مع التنبيهات
function incrementCounter() {
    rosaryCount++;
    updateDisplay();
    localStorage.setItem('rosary_val', rosaryCount);
    
    if (navigator.vibrate) navigator.vibrate(40);

    // نظام الرسائل (كل 30 و عند الـ 100)
    if (rosaryCount % 10 === 0 && rosaryCount !== 100) {
        const randomMsg = motivationMessages[Math.floor(Math.random() * motivationMessages.length)];
        Swal.fire({
            title: randomMsg,
            icon: 'success',
            background: '#1e293b',
            color: '#74F1D9',
            timer: 1500,
            showConfirmButton: false,
            toast: true,
            position: 'top'
        });
    } else if (rosaryCount === 100) {
        Swal.fire({
            title: '🎉 اكتملت المائة 🎉',
            html: '<p style="color:#fff">قال ﷺ: "أحب الكلام إلى الله أربع: سبحان الله، والحمد لله، ولا إله إلا الله، والله أكبر"</p>',
            icon: 'success',
            background: '#1e293b',
            confirmButtonColor: '#74F1D9'
        });
    }
}

// 7. دالة التصفير
function resetCounter() {
    Swal.fire({
        title: 'تصفير العداد؟',
        icon: 'warning',
        showCancelButton: true,
        confirmButtonColor: '#e74c3c',
        confirmButtonText: 'نعم',
        cancelButtonText: 'إلغاء',
        background: '#1e293b',
        color: '#fff'
    }).then((result) => {
        if (result.isConfirmed) {
            rosaryCount = 0;
            updateDisplay();
            localStorage.setItem('rosary_val', 0);
        }
    });
}














