let booksAlreadyRendered = false;

function fetchIslamicBooks() {
  if (booksAlreadyRendered) return;
  renderBooks(myCustomBooks);
}

function renderBooks(allBooks) {
  const booksGrid = document.getElementById('books-grid');
  if (!booksGrid) return;
  
  booksGrid.innerHTML = '';
  
  // الحل الأول: توسيع الشبكة لـ 240px لفك "اللزقة" تماماً
  booksGrid.style.cssText = `
        display: grid;
        grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
        gap: 30px;
        padding: 25px;
    `;
  
  const fragment = document.createDocumentFragment();
  
  allBooks.forEach(book => {
    // الحل الثاني: شلنا الـ substring عشان الاسم يظهر كامل
    const card = document.createElement('div');
    card.className = 'hadith-card';
    
    card.style.cssText = `
            cursor: pointer;
            background: rgba(255, 255, 255, 0.07);
            border-radius: 18px;
            padding: 10px;
            display: flex;
            flex-direction: column;
            align-items: center;
            transition: transform 0.2s ease, background 0.2s ease;
            border-bottom: 9px solid #ffffff;
            box-shadow: 0 10px 20px rgba(0,0,0,0.3);
            will-change: transform;
        `;
    
    card.onmouseover = () => {
      card.style.transform = "translateY(-8px)";
      card.style.background = "rgba(255, 255, 255, 0.12)";
    };
    card.onmouseout = () => {
      card.style.transform = "translateY(0)";
      card.style.background = "rgba(255, 255, 255, 0.07)";
    };
    
    card.onclick = () => window.open(book.previewLink, '_blank');
    
    card.innerHTML = `
            <div style="width: 160px; height: 230px; overflow: hidden; border-radius: 12px; margin-bottom: 15px; background: #1a1a1a; box-shadow: 0 6px 12px rgba(0,0,0,0.5);">
                <img src="${book.thumbnail}" loading="lazy" 
                     style="width: 100%; height: 100%; object-fit: cover;" 
                     onerror="this.src='https://via.placeholder.com/160x230?text=كتاب';">
            </div>
            
            <h4 style="color: white; font-size: 1rem; text-align: center; margin: 5px 0; height: auto; min-height: 40px; width: 100%; line-height: 1.4; font-weight: bold;">
                ${book.title}
            </h4>
            
            <p style="color: green; font-size: 0.85rem; text-align: center; opacity: 0.9; margin-top: 5px; font-weight: bold;">
                ${book.author}
            </p>
        `;
    
    fragment.appendChild(card);
  });
  
  booksGrid.appendChild(fragment);
  booksAlreadyRendered = true;
}

