let currentPage = localStorage.getItem('quranPage') ? parseInt(localStorage.getItem('quranPage')) : 1;
let selectedReciter = "Yasser_Ad-Dussary_128kbps"; 

// التعديل السحري هنا: إنشاء مشغل صوت (واحد فقط) ثابت على مستوى التطبيق
let currentAudio = new Audio(); 
let longPressTimer;

// 2. تحديث نص الكارت
function updateKhatmaCard() {
    const statusText = document.getElementById('khatmaStatus');
    if (statusText) statusText.innerText = `وصلت لصفحة رقم ${currentPage}`;
}

// 3. التحكم في الواجهة
function openKhatma() {
    document.getElementById('khatmaPage').style.display = 'block';
    document.body.style.overflow = 'hidden';
}

function closeKhatma() {
    stopAudio();
    document.getElementById('khatmaPage').style.display = 'none';
    document.body.style.overflow = 'auto';
}

// إيقاف الصوت بشكل قاطع
function stopAudio() {
    currentAudio.pause();
    currentAudio.currentTime = 0; // تصفير وقت الصوت
}

// 4. جلب بيانات الصفحة مع دعم الضغط المطول
async function startKhatmaProject() {
    Swal.fire({ title: 'جاري جلب الورد...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
    try {
        const response = await fetch(`https://api.alquran.cloud/v1/page/${currentPage}/quran-uthmani`);
        const data = await response.json();
        const pageData = data.data;

        document.getElementById('pageTitle').innerText = `${pageData.ayahs[0].surah.name} - صفحة ${currentPage}`;
        
        const fullPageContent = document.getElementById('fullPageContent');
        fullPageContent.innerHTML = pageData.ayahs.map(ayah => 
            `<span id="ayah-${ayah.number}" 
                   class="quran-ayah"
                   style="cursor:pointer; transition: 0.3s; display:inline-block; margin: 0 2px; padding: 4px 8px; border-radius: 8px;" 
                   onclick="playSingleAyah(${ayah.surah.number}, ${ayah.numberInSurah}, ${ayah.number})"
                   onmousedown="startLongPress(${ayah.number})"
                   onmouseup="cancelLongPress()"
                   onmouseleave="cancelLongPress()"
                   ontouchstart="startLongPress(${ayah.number})"
                   ontouchend="cancelLongPress()"
                   oncontextmenu="event.preventDefault();"
                   title="ضغطة عادية للصوت - مطولة للتفسير">
                ${ayah.text} ﴿${ayah.numberInSurah}﴾ 
            </span>`
        ).join(' ');

        document.getElementById('mainAudioBtn').onclick = showRecitersList;
        Swal.close();
        openKhatma();
    } catch (e) {
        Swal.fire('خطأ', 'تأكد من الإنترنت ', 'error');
    }
}

// 5. منطق الضغط المطول (Long Press)
function startLongPress(ayahNumber) {
    longPressTimer = setTimeout(() => {
        getTafsir(ayahNumber);
    }, 600); // مدة الضغطة المطولة (600 مللي ثانية)
}

function cancelLongPress() {
    clearTimeout(longPressTimer);
}

// 6. تشغيل آية واحدة
function playSingleAyah(surahNum, ayahInSurah, globalAyahNum) {
    stopAudio(); // نوقف أي حاجة شغالة الأول
    
    document.querySelectorAll('.quran-ayah').forEach(s => {
        s.style.backgroundColor = 'transparent';
        s.style.color = '#fff';
    });
    
    const currentSpan = document.getElementById(`ayah-${globalAyahNum}`);
    if (currentSpan) {
        currentSpan.style.backgroundColor = 'rgba(116, 241, 217, 0.15)';
        currentSpan.style.color = '#74F1D9';
    }

    const sNum = String(surahNum).padStart(3, '0');
    const aNum = String(ayahInSurah).padStart(3, '0');
    const audioUrl = `https://everyayah.com/data/${selectedReciter}/${sNum}${aNum}.mp3`;

    // بنغير المسار جوه نفس المشغل الأساسي بدل ما نفتح واحد جديد
    currentAudio.src = audioUrl;
    currentAudio.play().catch(() => {
        console.log("Audio play error");
    });
}

// 7. قائمة القراء الاحترافية
function showRecitersList() {
    const reciters = {
        "Yasser_Ad-Dussary_128kbps": "الشيخ ياسر الدوسري",
        "Alafasy_128kbps": "الشيخ مشاري العفاسي",
        "Husary_128kbps": "الشيخ محمود خليل الحصري"
    };

    Swal.fire({
        title: '<span style="color: #74F1D9; font-family: sans-serif;">اختر القارئ</span>',
        html: `
            <style>
                .swal2-radio {
                    display: flex !important;
                    flex-direction: column !important;
                    align-items: flex-start !important;
                    background: #252930 !important;
                    padding: 10px !important;
                    border-radius: 10px !important;
                    gap: 10px !important;
                }
                .swal2-radio label {
                    color: #fff !important; 
                    font-size: 1rem !important;
                    margin: 5px 0 !important;
                    display: flex !important;
                    align-items: center !important;
                    gap: 10px !important;
                    cursor: pointer !important;
                    width: 100% !important;
                }
                .swal2-radio input {
                    margin: 0 !important;
                    accent-color: #74F1D9 !important; 
                }
            </style>
            <p style="color: #bbb; font-size: 0.9rem; margin-bottom: 15px;">سيتم استخدام هذا القارئ عند الضغط على الآيات</p>
        `,
        input: 'radio',
        inputOptions: reciters,
        inputValue: selectedReciter,
        confirmButtonText: 'تأكيد الاختيار',
        confirmButtonColor: '#74F1D9',
        background: '#1a1d23',
        color: '#fff',
        target: document.getElementById('khatmaPage'),
        customClass: {
            input: 'custom-swal-input'
        }
    }).then((result) => {
        if (result.isConfirmed && result.value) {
            stopAudio(); // قفل الصوت الحالي بمجرد اختيار قارئ جديد
            selectedReciter = result.value;
            Swal.fire({ 
                title: ' تم التغيير', 
                icon: 'success', 
                timer: 1000, 
                showConfirmButton: false, 
                background: '#1a1d23', 
                color: '#fff',
                target: document.getElementById('khatmaPage') 
            });
        }
    });
}

// 8. جلب التفسير
async function getTafsir(ayahNumber) {
    try {
        const tRes = await fetch(`https://api.alquran.cloud/v1/ayah/${ayahNumber}/ar.muyassar`);
        const tData = await tRes.json();
        
        Swal.fire({
            title: '<span style="color: #74F1D9">التفسير الميسر</span>',
            text: tData.data.text,
            confirmButtonText: 'إغلاق',
            confirmButtonColor: '#444',
            background: '#1a1d23',
            color: '#fff',
            target: document.getElementById('khatmaPage')
        });
    } catch (e) {
        console.log("Tafsir error");
    }
}

// الدوال المتبقية (التنقل، الإنهاء)
function changePage(step) {
    let newPage = currentPage + step;
    if (newPage >= 1 && newPage <= 604) {
        currentPage = newPage;
        localStorage.setItem('quranPage', currentPage);
        updateKhatmaCard();
        startKhatmaProject();
    }
}

function finishReading() {
    currentPage++;
    localStorage.setItem('quranPage', currentPage);
    updateKhatmaCard();
    Swal.fire({ title: 'بارك اللّه فيك ', icon: 'success', timer: 2000, showConfirmButton: false, background: '#1a1d23', color: '#fff' });
    closeKhatma();
}

window.addEventListener('load', updateKhatmaCard);













