function openNawawi() {
    const modal = document.getElementById('nawawi-modal');
    if (modal) {
        modal.style.display = 'flex'; 
        modal.classList.add('active-modal'); 
        renderHadiths(); 
    }
}

function closeNawawi() {
    const modal = document.getElementById('nawawi-modal');
    if (modal) {
        modal.style.display = 'none';
        modal.classList.remove('active-modal');
    }
}

function getCompletedHadiths() {
    const completed = localStorage.getItem('nawawi_completed');
    return completed ? JSON.parse(completed) : [];
}

function toggleDone(id) {
    let completed = getCompletedHadiths();
    if (completed.includes(id)) {
        completed = completed.filter(item => item !== id);
    } else {
        completed.push(id);
    }
    localStorage.setItem('nawawi_completed', JSON.stringify(completed));
    renderHadiths(); 
}

// دالة إظهار وإخفاء الشرح بسلاسة
function toggleSharh(id) {
    const sharhDiv = document.getElementById(`sharh-${id}`);
    const btn = document.getElementById(`btn-sharh-${id}`);
    
    if (sharhDiv.style.display === "none") {
        sharhDiv.style.display = "block";
        btn.innerHTML = '<i class="fas fa-eye-slash"></i> إخفاء الشرح';
    } else {
        sharhDiv.style.display = "none";
        btn.innerHTML = '<i class="fas fa-book-open"></i> عرض الشرح';
    }
}

function renderHadiths() {
    const list = document.getElementById('hadith-list');
    const completedList = getCompletedHadiths();

    if (!list) return;

    list.innerHTML = nawawiData.map(h => {
        const isDone = completedList.includes(h.id);
        return `
            <div class="hadith-item-card ${isDone ? 'completed-hadith' : ''}">
                <div class="hadith-header">
                    <span class="hadith-title">الحديث ${h.id}: ${h.title}</span>
                    <i class="fas fa-check-circle done-icon" 
                       style="display: ${isDone ? 'inline-block' : 'none'}; color: var(--neon-accent);"></i>
                </div>

                <!-- نص الحديث يعرض مباشرة لراحة القارئ -->
                <div class="hadith-text-preview font-amiri" style="margin-bottom: 15px;">
                    ${h.text}
                </div>

                <!-- منطقة الشرح المخفية -->
                <div id="sharh-${h.id}" class="sharh-box" style="display: none; background: rgba(0,0,0,0.2); padding: 15px; border-radius: 12px; margin-bottom: 15px; border-right: 3px solid var(--neon-accent);">
                    <p class="font-cairo" style="font-size: 0.95rem; color: #ccc; line-height: 1.7;">
                        <strong style="color: var(--neon-accent); display: block; margin-bottom: 5px;">الشرح:</strong>
                        ${h.sharh}
                    </p>
                </div>

                <div class="hadith-actions" style="display: flex; gap: 10px;">
                    <button id="btn-sharh-${h.id}" onclick="toggleSharh(${h.id})" class="btn-sharh font-cairo">
                        <i class="fas fa-book-open"></i> عرض الشرح
                    </button>
                    <button onclick="toggleDone(${h.id})" class="btn-done font-cairo" 
                            style="background: ${isDone ? 'var(--neon-accent)' : 'rgba(255,255,255,0.1)'}; 
                                   color: ${isDone ? '#000' : '#fff'};">
                        ${isDone ? 'تمت القراءة' : 'قرأته'}
                    </button>
                </div>
            </div>
        `;
    }).join('');
}








// 1. قاعدة بيانات الأصوات (روابط مباشرة للأذان)
const adhanVoices = {
    mishary: "https://server8.mp3quran.net/adhan/01.mp3", // مشاري العفاسي
    madina: "https://server14.mp3quran.net/adhan/02.mp3", // أذان المدينة
    makkah: "https://server14.mp3quran.net/adhan/03.mp3", // أذان مكة
    abdulbasit: "https://server14.mp3quran.net/adhan/04.mp3" // عبد الباسط
};

// 2. المتغيرات الأساسية
let lastTriggeredMinute = ""; // لمنع تكرار الأذان في نفس الدقيقة

// 3. تهيئة التطبيق عند التحميل
document.addEventListener('DOMContentLoaded', () => {
    // طلب إذن الإشعارات من المستخدم
    if ("Notification" in window) {
        Notification.requestPermission();
    }
    
    // بدء المحرك الذي يفحص الوقت كل ثانية
    setInterval(updateClockAndCheckAdhan, 1000);
});

// 4. المحرك الرئيسي (الساعة وفحص التوقيت)
function updateClockAndCheckAdhan() {
    const now = new Date();
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    const currentTime = `${hours}:${minutes}`;

    // تحديث الساعة في واجهتك (لو عندك عنصر له هذا الـ ID)
    const clockElement = document.getElementById('digital-clock');
    if (clockElement) clockElement.innerText = `${hours}:${minutes}:${String(now.getSeconds()).padStart(2, '0')}`;

    // فحص الأذان (يتم مرة واحدة فقط كل دقيقة)
    if (currentTime !== lastTriggeredMinute) {
        checkPrayerMatch(currentTime);
    }
}

// 5. مقارنة الوقت الحالي بمواقيت الصلاة
function checkPrayerMatch(currentTime) {
    // افترضنا أن مواقيت الصلاة مخزنة في localStorage من الـ API الخاص بك
    const prayerTimes = JSON.parse(localStorage.getItem('prayerTimes')); 
    
    if (!prayerTimes) return;

    // أسماء الصلوات للبحث عنها
    const prayers = {
        "Fajr": "الفجر",
        "Dhuhr": "الظهر",
        "Asr": "العصر",
        "Maghrib": "المغرب",
        "Isha": "العشاء"
    };

    for (let key in prayers) {
        if (prayerTimes[key] === currentTime) {
            startAdhanProcess(prayers[key]);
            lastTriggeredMinute = currentTime;
            break;
        }
    }
}

// 6. تشغيل الأذان والنافذة المنبثقة
function startAdhanProcess(prayerName) {
    const audio = document.getElementById('adhan-audio');
    const overlay = document.getElementById('adhan-overlay');
    const nameTag = document.getElementById('current-prayer-name');

    // اختيار الصوت المفضل من الإعدادات أو الافتراضي
    const savedVoice = localStorage.getItem('preferredAdhan') || adhanVoices.mishary;
    audio.src = savedVoice;

    // إظهار النافذة
    nameTag.innerText = `حان الآن موعد أذان ${prayerName}`;
    overlay.style.display = 'flex';
    overlay.classList.add('active-overlay'); // لإضافة أنيميشن لو أحببت

    // تشغيل الصوت
    audio.play().catch(e => console.log("التشغيل التلقائي ممنوع، بانتظار تفاعل المستخدم"));

    // إرسال إشعار للنظام
    if (Notification.permission === "granted") {
        new Notification("🕌 نداء الصلاة", {
            body: `حان الآن موعد أذان ${prayerName}`,
            icon: "logo.png" // ضع مسار لوجو تطبيقك هنا
        });
    }
}

// 7. دالة إيقاف الأذان
function stopAdhan() {
    const audio = document.getElementById('adhan-audio');
    const overlay = document.getElementById('adhan-overlay');
    
    audio.pause();
    audio.currentTime = 0;
    overlay.style.display = 'none';
}

// 8. وظيفة تغيير صوت المؤذن (تستدعى من قائمة الإعدادات)
function setAdhanVoice(voiceKey) {
    if (adhanVoices[voiceKey]) {
        localStorage.setItem('preferredAdhan', adhanVoices[voiceKey]);
        
        // تجربة الصوت للمستخدم عند الاختيار
        const audio = document.getElementById('adhan-audio');
        audio.src = adhanVoices[voiceKey];
        audio.play();
        setTimeout(() => audio.pause(), 5000); // إيقاف بعد 5 ثواني (تجربة فقط)

        Swal.fire({
            title: 'تم الحفظ',
            text: 'سيتم رفع الأذان بهذا الصوت في الصلوات القادمة',
            icon: 'success',
            confirmButtonColor: 'var(--neon-accent)'
        });
    }
}









document.addEventListener("DOMContentLoaded", function() {
    const colorDots = document.querySelectorAll('.color-dot');
    
    // 1. التحقق من وجود لون محفوظ مسبقاً في الذاكرة عند فتح التطبيق
    const savedColor = localStorage.getItem('appAccentColor');
    if (savedColor) {
        // تطبيق اللون المحفوظ على المتغير الأساسي في CSS
        document.documentElement.style.setProperty('--neon-accent', savedColor);
        document.documentElement.style.setProperty('--nav-active-color', savedColor);
        
        // تحديث تأثير خلفية الأزرار النشطة ليتماشى مع اللون الجديد (opacity 12%)
        document.documentElement.style.setProperty('--nav-active-bg', hexToRgbA(savedColor, 0.12));
        
        // نقل كلاس النشاط (active) للدائرة الصحيحة
        colorDots.forEach(dot => {
            if(dot.getAttribute('data-color') === savedColor) {
                dot.classList.add('active');
            } else {
                dot.classList.remove('active');
            }
        });
    }

    // 2. الاستماع لحدث الضغط على دوائر الألوان
    colorDots.forEach(dot => {
        dot.addEventListener('click', function() {
            const selectedColor = this.getAttribute('data-color');
            
            // تغيير قيم الـ CSS Variables فوراً
            document.documentElement.style.setProperty('--neon-accent', selectedColor);
            document.documentElement.style.setProperty('--nav-active-color', selectedColor);
            document.documentElement.style.setProperty('--nav-active-bg', hexToRgbA(selectedColor, 0.12));
            
            // حفظ الخيار في LocalStorage
            localStorage.setItem('appAccentColor', selectedColor);
            
            // تحديث الشكل الجمالي للدوائر
            colorDots.forEach(d => d.classList.remove('active'));
            this.classList.add('active');
        });
    });

    // دالة مساعدة لتحويل الـ Hex إلى RGBA لضبط شفافية خلفية أزرار الـ Navigation
    function hexToRgbA(hex, opacity){
        let c;
        if(/^#([A-Fa-f0-9]{3}){1,2}$/.test(hex)){
            c= hex.substring(1).split('');
            if(c.length== 3){
                c= [c[0], c[0], c[1], c[1], c[2], c[2]];
            }
            c= '0x'+c.join('');
            return 'rgba('+[(c>>16)&255, (c>>8)&255, c&255].join(',')+','+opacity+')';
        }
        return 'rgba(255, 215, 0, 0.12)'; // القيمة الافتراضية في حال حدوث خطأ
    }
});







