document.addEventListener('DOMContentLoaded', () => {
    // 1. تهيئة نظام الصوت برمجياً
    window.audioCtx = new (window.AudioContext || window.webkitAudioContext)();

    // 2. إنشاء حاضنة الإشعارات المنبثقة داخل التطبيق
    createToastContainer();

    // 3. طلب إذن نظام التشغيل لإرسال إشعارات خارجية للموبايل (لو لم يتم تفعيلها من قبل)
    if ("Notification" in window && Notification.permission !== "granted") {
        Notification.requestPermission();
    }

    // 4. بدء تشغيل نظام الأذكار بالتوقيت الافتراضي الموحد وهو (3 دقائق)
    startCustomReminders(currentIntervalTime);
});

// دالة إرسال التنبيه الذكية (تتحقق أولاً هل المستخدم في الصفحة الرئيسية أم لا)
function sendLocalNotification(title, bodyText) {
    const mainUi = document.getElementById('main-prayer-ui');
    
    // إذا كانت الشاشة الرئيسية مخفية أو التطبيق شغال في الخلفية (user minimized the app)
    // هنقوم فوراً بتحويل الإشعار للخارج عشان يظهر في إشعارات الموبايل بالعبارات المخصصة
    if ((mainUi && mainUi.style.display === 'none') || document.hidden) {
        console.log("تم تحويل التنبيه إلى إشعار خارجي لأنك خارج الواجهة الرئيسية أو قفلت التطبيق.");
        sendExternalNotification();
        return; 
    }

    // تشغيل نغمة خفيفة مصاحبة للإشعار الداخلي
    playNotificationSound();

    // عرض الإشعار الزجاجي الاحترافي داخل التطبيق
    const container = document.getElementById('toast-container');
    if (container) {
        const toast = document.createElement('div');
        toast.style.cssText = `
            background: rgba(255, 255, 255, 0.15);
            backdrop-filter: blur(15px);
            -webkit-backdrop-filter: blur(15px);
            border: 1px solid rgba(255, 255, 255, 0.25);
            color: #ffffff;
            padding: 15px;
            margin-top: 10px;
            border-radius: 12px;
            box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.3);
            direction: rtl;
            text-align: right;
            animation: slideIn 0.5s ease-out;
        `;
        
        toast.innerHTML = `
            <strong style="color: #00ffcc; display: block; margin-bottom: 5px; font-size: 16px;">${title}</strong>
            <span style="font-size: 14px; line-height: 1.5;">${bodyText}</span>
        `;
        
        container.appendChild(toast);

        // اختفاء الإشعار الداخلي بعد 6 ثوانٍ تلقائياً
        setTimeout(() => {
            toast.style.opacity = '0';
            toast.style.transition = 'opacity 0.5s ease';
            setTimeout(() => toast.remove(), 500);
        }, 6000);
    }
}

// دالة إرسال الإشعارات الخارجية للنظام (تظهر على شاشة القفل والـ Notification Bar للموبايل)
function sendExternalNotification() {
    if ("Notification" in window && Notification.permission === "granted") {
        // باقة الأذكار الخارجية المخصصة برة التطبيق
        const externalMessages = [
            "هل قرأت وردك اليوم؟ 📖",
            "هل قرأت أذكارك اليوم؟ 📿",
            "جدد عهدك مع الله واقرأ أذكارك الآن 🌿",
            "صَلِّ على نبينا محمد ﷺ 💫",
            "لا تنسَ ذكر الله اليوم ✨"
        ];
        
        // اختيار عبارة عشوائية من القائمة الخارجية
        const randomExternalText = externalMessages[Math.floor(Math.random() * externalMessages.length)];
        
        new Notification("تذكير بذكر الله 🌙", {
            body: randomExternalText,
            icon: "ysr.jpg" // يمكنك وضع مسار أيقونة تطبيقك الافتراضية هنا لتظهر في الإشعار
        });
    }
}

// دالة التحكم وتشغيل العداد الزمني (وتصفير العداد السابق عند التغيير)
function startCustomReminders(timeInMs) {
    if (thikrInterval) clearInterval(thikrInterval);
    
    thikrInterval = setInterval(() => {
        const randomItem = athkarList[Math.floor(Math.random() * athkarList.length)];
        sendLocalNotification(randomItem.title, randomItem.text);
    }, timeInMs);
}

// دالة اختيار توقيت ظهور الإشعار (متروكة كما هي لمرونة التغيير البرمجي من الأزرار)
function changeNotificationPeriod(seconds) {
    currentIntervalTime = seconds * 1000;
    startCustomReminders(currentIntervalTime);
    console.log(`تم تحديث توقيت ظهور الأذكار بنجاح ليصبح كل: ${seconds} ثانية.`);
}

// دالة توليد صوت التنبيه برمجياً
function playNotificationSound() {
    try {
        const osc = window.audioCtx.createOscillator();
        const gain = window.audioCtx.createGain();
        osc.connect(gain);
        gain.connect(window.audioCtx.destination);
        osc.type = 'sine';
        osc.frequency.value = 587.33; 
        gain.gain.setValueAtTime(0.08, window.audioCtx.currentTime);
        osc.start();
        osc.stop(window.audioCtx.currentTime + 0.15); 
    } catch (e) {
        console.log("تشغيل الصوت ينتظر تفاعل المستخدم.");
    }
}

// إنشاء الحاضنة الخاصة بالإشعارات المنبثقة
function createToastContainer() {
    if (!document.getElementById('toast-container')) {
        const container = document.createElement('div');
        container.id = 'toast-container';
        container.style.cssText = `
            position: fixed;
            bottom: 90px;
            left: 20px;
            right: 20px;
            z-index: 9999;
            display: flex;
            flex-direction: column-reverse;
        `;
        document.body.appendChild(container);

        const style = document.createElement('style');
        style.innerHTML = `
            @keyframes slideIn {
                from { transform: translateY(50px); opacity: 0; }
                to { transform: translateY(0); opacity: 1; }
            }
        `;
        document.head.appendChild(style);
    }
}












