// 1. قاعدة بيانات السير العطرة للصحابة
// قاعدة بيانات الصحابة
function setActive(navElement, sectionId) {
    // 1. إزالة كلاس النشاط من كل الأزرار
    document.querySelectorAll('.nav-item').forEach(item => item.classList.remove('active'));
    
    // إضافة كلاس النشاط للزر المضغوط
    if (navElement) navElement.classList.add('active');

    // 2. إخفاء جميع الأقسام
    document.querySelectorAll('.section').forEach(sec => {
        sec.style.display = 'none';
    });

    // 3. إظهار القسم المطلوب
    if (sectionId === 'main') {
        document.getElementById('main-prayer-ui').style.display = 'block';
    } else if (sectionId === 'hadith') {
        document.getElementById('hadith-section').style.display = 'block';
    } else if (sectionId === 'quran') {
        document.getElementById('quran-list-section').style.display = 'block';
    } else if (sectionId === 'sahaba') {
        document.getElementById('sahaba-section').style.display = 'block';
        loadSahabaList(); // تشغيل دالة بناء القائمة عند فتح القسم
    } else if (sectionId === 'tasks') {
        openTasks();
    }
}

