// دالة الفلترة (تستدعى عند الكتابة في حقل البحث)
function filterSahaba(searchTerm) {
    const container = document.getElementById('sahaba-list');
    container.innerHTML = ''; // تنظيف القائمة

    // فلترة البيانات
    const filteredData = sahabaData.filter(sahabi => 
        sahabi.name.includes(searchTerm) || sahabi.title.includes(searchTerm)
    );

    // إعادة بناء القائمة بناءً على النتيجة
    filteredData.forEach(sahabi => {
        const card = document.createElement('div');
        card.className = 'sahabi-card';
        card.innerHTML = `<h3>${sahabi.name}</h3><p>${sahabi.title}</p>`;
        
        card.onclick = () => {
            showSahabaModal(sahabi); // دالة عرض المودال (سأعطيك كودها أدناه)
        };
        container.appendChild(card);
    });
}

// دالة عرض المودال (لتقليل التكرار)
function showSahabaModal(sahabi) {
    const modal = document.createElement('div');
    modal.className = 'sahaba-popup-modal';
    modal.innerHTML = `
        <div class="sahaba-popup-content">
            <h2 style="color: var(--neon-accent)">${sahabi.name}</h2>
            <h4>${sahabi.title}</h4>
            <p>${sahabi.story}</p>
            <button class="sahaba-close-btn" onclick="this.parentElement.parentElement.remove()">إغلاق</button>
        </div>
    `;
    document.body.appendChild(modal);
}

// تعديل الدالة الأصلية للتحميل
function loadSahabaList() {
    filterSahaba(''); // استدعاء دالة الفلترة بنص فارغ لعرض الجميع في البداية
}

















