/**
 * دالة عرض سنة اليوم بناءً على تاريخ الجهاز الحالي
 */
/**
 * دالة عرض سنة نبوية عشوائية ومتجددة في كل مرة يفتح فيها التطبيق
 */
function displaySunnahOfTheDay() {
    const titleEl = document.getElementById('sunnah-title');
    const hadithEl = document.getElementById('sunnah-hadith');
    const narratorEl = document.getElementById('sunnah-narrator');
    const sourceEl = document.getElementById('sunnah-source');

    // تأمين الحساب في حال عدم وجود العناصر بالصفحة
    if (!titleEl || !hadithEl || !narratorEl || !sourceEl) return;

    // 1. جلب رقم السُّنّة التي ظهرت للمستخدم في المرة السابقة (إن وجدت)
    const lastIndex = sessionStorage.getItem('lastSunnahIndex');
    let randomIndex;

    // 2. حلقة تكرار ذكية لاختيار رقم عشوائي جديد بشرط ألا يتكرر مع المرة السابقة
    do {
        randomIndex = Math.floor(Math.random() * sunnahDatabase.length);
    } while (randomIndex == lastIndex && sunnahDatabase.length > 1);

    // 3. حفظ رقم السنة الحالية في ذاكرة الجلسة للمرة القادمة
    sessionStorage.setItem('lastSunnahIndex', randomIndex);

    // 4. جلب بيانات السنة المختارة
    const todaySunnah = sunnahDatabase[randomIndex];

    // 5. طباعة وتحديث البيانات في واجهة التطبيق فوراً
    titleEl.innerText = todaySunnah.title;
    hadithEl.innerText = todaySunnah.hadith;
    narratorEl.innerHTML = `<i class="fas fa-user"></i> الراوي: ${todaySunnah.narrator}`;
    sourceEl.innerText = todaySunnah.source;
}

// تشغيل الدالة تلقائياً بمجرد تحميل واجهة التطبيق أو عمل Refresh
window.addEventListener('DOMContentLoaded', displaySunnahOfTheDay);















