// المتغيرات للتحكم في التشغيل
let currentAyahIndex = -1;
let isAyahAudioPlaying = false;

/**
 * دالة جلب وعرض آية عشوائية دون تكرار متتالي
 */
function loadRandomAyah() {
    // إيقاف الصوت الحالي تماماً لو كان يعمل
    const audioPlayer = document.getElementById('ayah-audio-player');
    if(audioPlayer) {
        audioPlayer.pause();
    }
    onAudioEnded();

    let nextIndex;
    // حلقة تكرار لضمان عدم اختيار نفس الآية
    do {
        nextIndex = Math.floor(Math.random() * quranTadaborDatabase.length);
    } while (nextIndex === currentAyahIndex && quranTadaborDatabase.length > 1);

    currentAyahIndex = nextIndex;
    const currentAyah = quranTadaborDatabase[currentAyahIndex];

    // تحديث الواجهة
    document.getElementById('ayah-text').innerText = currentAyah.text;
    document.getElementById('ayah-lesson').innerText = currentAyah.lesson;
    document.getElementById('ayah-reference').innerText = currentAyah.reference;
    
    // ربط ملف الصوت الجديد
    if(audioPlayer) {
        audioPlayer.src = currentAyah.audioUrl;
        audioPlayer.load();
    }
}

/**
 * دالة التحكم في تشغيل وإيقاف صوت الآية (تم تصحيح الاسم ليتطابق مع زر الـ HTML)
 */
function toggleAyahAudio() {
    const audioPlayer = document.getElementById('ayah-audio-player');
    const playIcon = document.getElementById('play-icon');
    const playBtn = document.getElementById('play-ayah-btn');

    // إذا لم يكن هناك عنصر صوت في الصفحة، أوقِف الدالة
    if (!audioPlayer) return;

    if (!isAyahAudioPlaying) {
        // بدء التشغيل وتغيير الأيقونة لانتظار التحميل
        playIcon.className = "fas fa-spinner fa-spin";
        playBtn.style.background = "#ffd166";
        
        audioPlayer.play()
            .then(() => {
                isAyahAudioPlaying = true;
                playIcon.className = "fas fa-pause";
                playBtn.innerHTML = `<i id="play-icon" class="fas fa-pause"></i> إيقاف مؤقت`;
                playBtn.style.background = "#ff5e5e";
                playBtn.style.color = "#fff";
            })
            .catch(error => {
                console.error("خطأ في تشغيل الصوت:", error);
                playIcon.className = "fas fa-play";
                playBtn.style.background = "#00E676";
                playBtn.style.color = "#0f172a";
                alert("تعذر تحميل الصوت، تأكد من اتصالك بالإنترنت.");
            });
    } else {
        // إيقاف التشغيل
        audioPlayer.pause();
        onAudioEnded();
    }
}

/**
 * دالة إعادة الأزرار لطبيعتها عند انتهاء الصوت أو تغييره
 */
function onAudioEnded() {
    isAyahAudioPlaying = false;
    const playBtn = document.getElementById('play-ayah-btn');
    if (playBtn) {
        playBtn.innerHTML = `<i id="play-icon" class="fas fa-play"></i> استمع للدوسري`;
        playBtn.style.background = "#00E676";
        playBtn.style.color = "#0f172a";
    }
}

/**
 * دالة مشاركة الآية وتدبرها
 */
function shareAyah() {
    const currentAyah = quranTadaborDatabase[currentAyahIndex];
    const shareText = `✨ *آية وتدبر من تطبيق محراب* ✨\n\n📖 *الآية:* ${currentAyah.text}\n📍 *المصدر:* ${currentAyah.reference}\n\n💡 *التدبر والعبرة:* ${currentAyah.lesson}\n\n`;

    if (navigator.share) {
        navigator.share({
            title: 'آية وتدبر - تطبيق محراب',
            text: shareText
        }).catch(err => console.log("تم إلغاء المشاركة"));
    } else {
        navigator.clipboard.writeText(shareText);
        Swal.fire({
            icon: 'success',
            title: 'تم نسخ النص المنسق!',
            text: 'يمكنك الآن لصقه ومشاركته.',
            confirmButtonText: 'حسناً',
            confirmButtonColor: '#00E676'
        });
    }
}

// تشغيل الواجهة تلقائياً
window.addEventListener('DOMContentLoaded', () => {
    setTimeout(loadRandomAyah, 100);
});










