// نظام الإشعارات الاحترافي (Toast)
// =============================================
function showToast(message, type = 'info', duration = 3500) {
    const existingToast = document.querySelector('.quran-toast');
    if (existingToast) existingToast.remove();

    const icons = {
        success: `<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>`,
        error:   `<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="15" y1="9" x2="9" y2="15"></line><line x1="9" y1="9" x2="15" y2="15"></line></svg>`,
        info:    `<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>`,
        bookmark:`<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"></path></svg>`
    };

    const colors = {
        success:  { bg: '#f0fdf4', border: '#86efac', text: '#166534', icon: '#22c55e' },
        error:    { bg: '#fef2f2', border: '#fca5a5', text: '#991b1b', icon: '#ef4444' },
        info:     { bg: '#fffbeb', border: '#fcd34d', text: '#92400e', icon: '#f59e0b' },
        bookmark: { bg: '#f0fdf4', border: '#86efac', text: '#166534', icon: '#16a34a' }
    };

    const c = colors[type] || colors.info;

    const toast = document.createElement('div');
    toast.className = 'quran-toast';
    toast.style.cssText = `
        position: fixed;
        top: 24px;
        left: 50%;
        transform: translateX(-50%) translateY(-20px);
        z-index: 99999;
        display: flex;
        align-items: center;
        gap: 12px;
        padding: 14px 22px;
        background: ${c.bg};
        border: 1.5px solid ${c.border};
        border-radius: 14px;
        color: ${c.text};
        font-family: 'Cairo', 'Segoe UI', sans-serif;
        font-size: 15px;
        font-weight: 600;
        direction: rtl;
        box-shadow: 0 8px 32px rgba(0,0,0,0.12), 0 2px 8px rgba(0,0,0,0.06);
        opacity: 0;
        transition: opacity 0.3s ease, transform 0.3s ease;
        min-width: 260px;
        max-width: 90vw;
        text-align: center;
        justify-content: center;
        backdrop-filter: blur(8px);
    `;

    const iconEl = document.createElement('span');
    iconEl.style.cssText = `color: ${c.icon}; display: flex; align-items: center; flex-shrink: 0;`;
    iconEl.innerHTML = icons[type] || icons.info;

    const textEl = document.createElement('span');
    textEl.textContent = message;

    toast.appendChild(iconEl);
    toast.appendChild(textEl);
    document.body.appendChild(toast);

    requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            toast.style.opacity = '1';
            toast.style.transform = 'translateX(-50%) translateY(0)';
        });
    });

    setTimeout(() => {
        toast.style.opacity = '0';
        toast.style.transform = 'translateX(-50%) translateY(-20px)';
        setTimeout(() => toast.remove(), 350);
    }, duration);
}

