// =============================================
// تحميل فهرس السور
// =============================================
function loadTanzilQuranData() {
    surahListContainer.innerHTML = `
        <div style="grid-column:1/-1; text-align:center; padding: 40px 20px; color:#11421e;">
            <div style="font-size:36px; margin-bottom:12px; animation: spin 1.5s linear infinite; display:inline-block;">☽</div>
            <p style="font-family:'Cairo',sans-serif; font-size:16px; margin:0;">جاري تحميل الفهرس...</p>
        </div>`;

    fetch('quran.json')
        .then(response => response.text())
        .then(text => {
            processTanzilText(text);
            renderSurahIndex();
        })
        .catch(error => {
            surahListContainer.innerHTML = `
                <div style="grid-column:1/-1; text-align:center; padding:40px 20px; color:#991b1b;">
                    <p style="font-family:'Cairo',sans-serif; font-size:16px;">عذرًا، تعذّر تحميل الفهرس. سيتم الاعتماد على الأرقام الافتراضية.</p>
                </div>`;
            console.error("Error loading Quran text:", error);
            renderSurahIndex(); // عرض الفهرس في كل الأحوال
        });
}

function processTanzilText(rawText) {
    const lines = rawText.split('\n');
    lines.forEach(line => {
        if (line.startsWith('#') || line.trim() === '') return;
        const parts = line.split('|');
        if (parts.length >= 3) {
            const surahId  = parseInt(parts[0]);
            const verseId  = parseInt(parts[1]);
            const verseText= parts[2].trim();
            if (!parsedQuranData[surahId]) {
                parsedQuranData[surahId] = { id: surahId, name: surahNames[surahId - 1], verses: [] };
            }
            parsedQuranData[surahId].verses.push({ id: verseId, text: verseText });
        }
    });
}

function renderSurahIndex() {
    surahListContainer.innerHTML = "";
    surahNames.forEach((name, index) => {
        const surahId = index + 1;
        const card = document.createElement('div');
        card.className = 'surah-card';
        card.innerHTML = `
            <span class="surah-number">${getArabicNumber(surahId)}</span>
            <span class="surah-title">سورة ${name}</span>
            <span class="surah-arrow">‹</span>`;

        card.addEventListener('click', () => {
            const startPage = surahStartPage[index];
            loadQuranPage(startPage);
        });
        surahListContainer.appendChild(card);
    });
}

// =============================================
// نظام تحميل الصفحات (604 صفحة) وتصغير الخط
// =============================================
function loadQuranPage(pageNum, scrollToBookmark = null) {
    mushafIndex.classList.add('quran-hidden');
    mushafReadingArea.classList.remove('quran-hidden');
    showIndexBtn.classList.remove('quran-hidden');

    mushafDynamicTitle.textContent = `الصفحة ${getArabicNumber(pageNum)}`;
    
    mushafTextContent.innerHTML = `
        <div style="text-align:center; padding: 40px; color:#11421e;">
            <div style="font-size:30px; animation: pulse 1s alternate infinite; display:inline-block;">☽</div>
            <p style="font-family:'Cairo', sans-serif;">جاري تحميل الصفحة ${getArabicNumber(pageNum)}...</p>
        </div>`;

    fetch(`https://api.alquran.cloud/v1/page/${pageNum}/quran-uthmani`)
        .then(res => res.json())
        .then(data => {
            if (data.code === 200) {
                renderPageContent(data.data.ayahs, pageNum, scrollToBookmark);
            }
        })
        .catch(err => {
            mushafTextContent.innerHTML = `<div style="text-align:center; padding:20px; color:#991b1b; font-family:'Cairo', sans-serif;">تعذّر تحميل الصفحة. يُرجى التحقق من الاتصال بالإنترنت.</div>`;
            console.error("Error loading page:", err);
        });
}

function renderPageContent(ayahs, pageNum, scrollToBookmark) {
    let fullText = "";
    let currentSurahName = "";

    ayahs.forEach((ayah) => {
        if (ayah.numberInSurah === 1) {
            currentSurahName = ayah.surah.name;
            fullText += `<div class="surah-frame-title" style="text-align:center; font-size:20px; font-weight:bold; margin: 25px 0 10px; color:#11421e; padding-bottom:8px; border-bottom: 2px solid rgba(17, 66, 30, 0.1);">سُورَةُ ${currentSurahName.replace('سورة ', '')}</div>`;

            if (ayah.surah.number !== 1 && ayah.surah.number !== 9) {
                fullText += `<div class="bismillah-header" style="text-align:center; font-size:18px; margin-bottom:10px; color:#1a3a1e;">بِسْمِ اللَّهِ الرَّحْمَٰنِ الرَّحِيمِ</div>`;
            }
        }

        let text = ayah.text;
        if (ayah.surah.number !== 1 && ayah.surah.number !== 9 && ayah.numberInSurah === 1) {
            text = text.replace(/^بِسْمِ.+?حِيمِ\s*/, "");
        }

        // تم تصغير الخط وتقليل التباعد لتجنب السكرول الطويل
        fullText += `<span id="verse-${ayah.surah.number}-${ayah.numberInSurah}" 
                           class="clickable-verse" 
                           data-surah="${ayah.surah.number}" 
                           data-verse="${ayah.numberInSurah}" 
                           data-sname="${ayah.surah.name.replace('سورة ', '')}" 
                           style="cursor:pointer; padding: 2px 4px; font-size: 18px; line-height: 1.8; transition: background-color 0.3s ease; user-select: none; -webkit-user-select: none;">
                           ${text} 
                           <span class="verse-ornament" style="color:#c5a059; font-size:0.85em; margin:0 2px;">۝${getArabicNumber(ayah.numberInSurah)}</span>
                     </span> `;
    });

    const navHTML = `
        <div style="display:flex; justify-content:space-between; align-items:center; margin-top:30px; padding-top:15px; border-top:1px solid #e0e0e0; font-family:'Cairo', sans-serif;">
            <button onclick="window.navigateQuranPage(${pageNum + 1})" ${pageNum >= 604 ? 'disabled' : ''} style="padding:8px 15px; background:${pageNum >= 604 ? '#ccc' : '#11421e'}; color:#fff; border:none; border-radius:8px; cursor:${pageNum >= 604 ? 'not-allowed' : 'pointer'}; font-weight:bold; font-size:14px; transition:0.3s;">الصفحة التالية ◂</button>
            <span style="font-weight:bold; font-size:16px; color:#11421e; background: rgba(17, 66, 30, 0.05); padding: 5px 12px; border-radius: 20px;">${getArabicNumber(pageNum)}</span>
            <button onclick="window.navigateQuranPage(${pageNum - 1})" ${pageNum <= 1 ? 'disabled' : ''} style="padding:8px 15px; background:${pageNum <= 1 ? '#ccc' : '#11421e'}; color:#fff; border:none; border-radius:8px; cursor:${pageNum <= 1 ? 'not-allowed' : 'pointer'}; font-weight:bold; font-size:14px; transition:0.3s;">▸ الصفحة السابقة</button>
        </div>
    `;

    mushafTextContent.innerHTML = fullText + navHTML;
    mushafScreen.scrollTop = 0;
    
    // تفعيل نظام اللمس الذكي على الآيات
    attachSmartTouchEvents();
    
    if (scrollToBookmark) {
        setTimeout(() => {
            const targetVerse = document.getElementById(`verse-${scrollToBookmark.surah}-${scrollToBookmark.verse}`);
            if (targetVerse) {
                targetVerse.scrollIntoView({ behavior: 'smooth', block: 'center' });
                targetVerse.style.backgroundColor = 'rgba(197, 160, 89, 0.4)';
                targetVerse.style.borderRadius = '6px';
                setTimeout(() => targetVerse.style.backgroundColor = 'transparent', 2500);
                showToast(`استأنفت القراءة عند سورة ${scrollToBookmark.surahName}`, 'success');
            }
        }, 500);
    }
}

window.navigateQuranPage = function(page) {
    if (page >= 1 && page <= 604) {
        loadQuranPage(page);
    }
};

function getArabicNumber(number) {
    const arabicDigits = ['٠', '١', '٢', '٣', '٤', '٥', '٦', '٧', '٨', '٩'];
    return String(number).split('').map(digit => arabicDigits[Number(digit)]).join('');
}

// =============================================
// نظام اللمس الذكي (Smart Touch Events)
// =============================================
function attachSmartTouchEvents() {
    const verses = document.querySelectorAll('.clickable-verse');
    
    verses.forEach(verse => {
        let pressTimer;
        let clickTimer;
        let preventClick = false;
        let clickCount = 0;

        const surah = verse.dataset.surah;
        const verseNum = verse.dataset.verse;
        const sName = verse.dataset.sname;

        // عند بدء اللمس (للضغطة المطولة)
        const startPress = (e) => {
            preventClick = false;
            pressTimer = setTimeout(() => {
                preventClick = true; 
                saveBookmarkAction(surah, verseNum, sName, verse);
            }, 600); // 600 ملي ثانية تعتبر ضغطة مطولة
        };

        const cancelPress = () => clearTimeout(pressTimer);

        verse.addEventListener('pointerdown', startPress);
        verse.addEventListener('pointermove', cancelPress);
        verse.addEventListener('pointercancel', cancelPress);
        verse.addEventListener('pointerleave', cancelPress);

        // عند رفع الإصبع (لتحديد هل هي ضغطة واحدة أم مزدوجة)
        verse.addEventListener('pointerup', (e) => {
            clearTimeout(pressTimer);
            if (preventClick) return; 

            clickCount++;
            if (clickCount === 1) {
                clickTimer = setTimeout(() => {
                    if (clickCount === 1) {
                        playDosariAudio(surah, verseNum, verse); // ضغطة واحدة
                    }
                    clickCount = 0;
                }, 300); 
            } else if (clickCount === 2) {
                clearTimeout(clickTimer);
                showIbnKathirTafsir(surah, verseNum, sName); // ضغطتين
                clickCount = 0;
            }
        });

        // منع القائمة الافتراضية عند الضغط المطول
        verse.addEventListener('contextmenu', e => e.preventDefault());
    });
}

// =============================================
// وظائف الأوامر (تلاوة - حفظ - تفسير)
// =============================================
function playDosariAudio(surah, verse, element) {
    const padZero = (num) => String(num).padStart(3, '0');
    const audioUrl = `https://everyayah.com/data/Yasser_Ad-Dussary_128kbps/${padZero(surah)}${padZero(verse)}.mp3`;
    
    dosariAudio.src = audioUrl;
    
    document.querySelectorAll('.clickable-verse').forEach(el => el.style.backgroundColor = 'transparent');
    
    element.style.backgroundColor = 'rgba(197, 160, 89, 0.3)';
    element.style.borderRadius = '6px';
    
    showToast('بصوت ياسر الدوسري 🎧', 'info', 1500);
    
    dosariAudio.play().catch(e => {
        showToast('يلزم الاتصال بالإنترنت لتشغيل التلاوة.', 'error');
        element.style.backgroundColor = 'transparent';
    });
}

function saveBookmarkAction(surah, verse, sName, element) {
    const bookmarkData = { surah: parseInt(surah), verse: parseInt(verse), surahName: sName };
    localStorage.setItem('quranBookmark', JSON.stringify(bookmarkData));
    
    element.style.backgroundColor = 'rgba(22, 163, 74, 0.3)'; // لون أخضر لتأكيد الحفظ
    element.style.borderRadius = '6px';
    setTimeout(() => element.style.backgroundColor = 'transparent', 1500);

    showToast(`تم حفظ علامتك عند سورة ${sName} — الآية ${verse}`, 'bookmark', 3000);
    dosariAudio.pause();
}

function showIbnKathirTafsir(surah, verse, sName) {
    let tafsirModal = document.getElementById('ibn-kathir-modal');
    if (!tafsirModal) {
        document.body.insertAdjacentHTML('beforeend', `
            <div id="ibn-kathir-modal" style="display:none; position:fixed; top:0; left:0; width:100%; height:100%; background:rgba(0,0,0,0.7); z-index:999999; justify-content:center; align-items:center;">
                <div style="background:#fff; width:92%; max-width:450px; max-height:80vh; border-radius:16px; display:flex; flex-direction:column; overflow:hidden; direction:rtl; font-family:'Cairo', sans-serif;">
                    <div style="background:#11421e; padding:15px 20px; color:#fff; display:flex; justify-content:space-between; align-items:center;">
                        <h3 id="tafsir-modal-title" style="margin:0; font-size:16px;">تفسير ابن كثير</h3>
                        <button onclick="document.getElementById('ibn-kathir-modal').style.display='none'" style="background:none; border:none; color:#c5a059; font-size:28px; cursor:pointer; line-height:1;">&times;</button>
                    </div>
                    <div id="tafsir-modal-content" style="padding:20px; overflow-y:auto; font-size:16px; line-height:2.2; color:#1a3a1e; text-align:justify;">
                        جاري التحميل...
                    </div>
                </div>
            </div>
        `);
        tafsirModal = document.getElementById('ibn-kathir-modal');
        tafsirModal.addEventListener('click', (e) => {
            if(e.target === tafsirModal) tafsirModal.style.display = 'none';
        });
    }

    document.getElementById('tafsir-modal-title').textContent = `تفسير ابن كثير - سورة ${sName} (${verse})`;
    document.getElementById('tafsir-modal-content').innerHTML = '<div style="text-align:center; color:#11421e; margin-top:20px;"><div style="font-size:28px; animation: spin 1.5s linear infinite; display:inline-block;">☽</div><p>جاري سحب تفسير ابن كثير...</p></div>';
    tafsirModal.style.display = 'flex';

    const apiUrl = `https://cdn.jsdelivr.net/gh/spa5k/tafsir_api@main/tafsir/ar-tafsir-ibn-kathir/${surah}/${verse}.json`;

    fetch(apiUrl)
        .then(res => res.json())
        .then(data => {
            document.getElementById('tafsir-modal-content').innerHTML = data.text;
        })
        .catch(err => {
            document.getElementById('tafsir-modal-content').innerHTML = '<p style="color:#ef4444; text-align:center;">عذرًا، تعذر تحميل التفسير. يرجى التحقق من اتصال الإنترنت الخاص بك.</p>';
        });
}

// =============================================
// الذهاب للعلامة المحفوظة
// =============================================
if (goBookmarkBtn) {
    goBookmarkBtn.addEventListener('click', () => {
        const saved = localStorage.getItem('quranBookmark');
        if (!saved) {
            showToast('لا توجد علامة محفوظة بعد. اضغط مطولاً على أي آية لحفظ علامتك.', 'info', 4000);
            return;
        }

        const bookmark = JSON.parse(saved);
        showToast('جاري الانتقال للعلامة المحفوظة...', 'info');

        fetch(`https://api.alquran.cloud/v1/ayah/${bookmark.surah}:${bookmark.verse}`)
            .then(res => res.json())
            .then(data => {
                if(data.code === 200) {
                    const pageNumber = data.data.page;
                    loadQuranPage(pageNumber, bookmark);
                    mushafScreen.classList.remove('quran-hidden'); // التأكد من فتح شاشة المصحف
                    document.body.style.overflow = 'hidden';
                }
            })
            .catch(err => {
                loadQuranPage(surahStartPage[bookmark.surah - 1], bookmark);
                mushafScreen.classList.remove('quran-hidden');
                document.body.style.overflow = 'hidden';
            });
    });
}








document.addEventListener('DOMContentLoaded', () => {
    const themeToggleBtn = document.getElementById('theme-toggle');
    const themeIcon = themeToggleBtn.querySelector('i');

    // 1. التحقق من وجود خيار محجوز مسبقاً في متصفح المستخدم
    const currentTheme = localStorage.getItem('theme');
    
    if (currentTheme === 'dark') {
        document.body.classList.add('dark-mode');
        updateIcon(true);
    } else {
        // الوضع الافتراضي للتطبيق (الفاتح كأوراق المصاحف التراثية)
        document.body.classList.remove('dark-mode');
        updateIcon(false);
    }

    // 2. حدث الضغط على الزرار للتبديل
    themeToggleBtn.addEventListener('click', () => {
        document.body.classList.toggle('dark-mode');
        
        // معرفة الوضع الحالي وحفظه في الـ LocalStorage
        const isDark = document.body.classList.contains('dark-mode');
        localStorage.setItem('theme', isDark ? 'dark' : 'light');
        
        // تحديث شكل الأيقونة
        updateIcon(isDark);
    });

    // دالة لتغيير الأيقونة حسب الوضع (هنا استخدمنا مكتبة Remix Icon كمثال)
    function updateIcon(isDark) {
        if (isDark) {
            themeIcon.className = 'ri-sun-line'; // أيقونة الشمس للعودة للوضع الفاتح
        } else {
            themeIcon.className = 'ri-moon-line'; // أيقونة الهلال للانتقال للوضع الداكن
        }
    }
});






function setTimeBasedBackground() {
    const currentHour = new Date().getHours();
    let bgImageUrl = "";

    // تقسيم اليوم إلى 4 فترات زمنية
    if (currentHour >= 5 && currentHour < 12) {
        // 1. فترة الصباح (من 5:00 صباحاً حتى 11:59 صباحاً)
        bgImageUrl = "url('11.png')";
    } else if (currentHour >= 12 && currentHour < 16) {
        // 2. فترة الظهر والعصر (من 12:00 ظهراً حتى 3:59 عصراً)
        bgImageUrl = "url('22.png')";
    } else if (currentHour >= 16 && currentHour < 19) {
        // 3. فترة الغروب (من 4:00 عصراً حتى 6:59 مساءً)
        bgImageUrl = "url('33.png')";
    } else {
        // 4. فترة الليل (من 7:00 مساءً حتى 4:59 فجراً)
        bgImageUrl = "url('44.png')";
    }

    // تطبيق المسار على المتغير البرمجي في الـ CSS
    document.body.style.setProperty('--dynamic-bg', bgImageUrl);
}

// تشغيل الدالة فور تحميل التطبيق
document.addEventListener('DOMContentLoaded', () => {
    setTimeBasedBackground();
    
    // تحديث الخلفية تلقائياً كل ساعة
    setInterval(setTimeBasedBackground, 3600000); 
});







// مصفوفة تحتوي على أشهر الإذاعات وروابط البث الحي المستقرة لها
// قائمة الإذاعات
// قائمة الإذاعات مع روابط السيرفر الرسمي المستقر (Qurango)
document.addEventListener('DOMContentLoaded', () => {
    // عناصر التنقل بين الصفحات المستقلة
    const btnGoToRadio = document.getElementById('btn-go-to-radio');
    const btnBackToHome = document.getElementById('btn-back-to-home');
    const btnBackToList = document.getElementById('btn-back-to-list');
    
    const pageRadioList = document.getElementById('page-radio-list');
    const pageRadioPlayer = document.getElementById('page-radio-player');

    // عناصر صفحة التحكم والمشغل
    const cardsContainer = document.getElementById('radio-cards-container');
    const searchInput = document.getElementById('radio-search');
    const fullPlayerTitle = document.getElementById('full-player-title');
    const fullPlayerStatus = document.getElementById('full-player-status');
    const btnFullToggle = document.getElementById('btn-full-toggle');
    const audioWaves = document.getElementById('audio-waves-container');

    // إنشاء كائن الصوت البرمي المستقل لحل مشاكل الهواتف
    let radioAudio = new Audio();
    radioAudio.crossOrigin = "anonymous"; 

    let allStations = []; // تخزين كافة الإذاعات
    let currentSelectedStation = null;

    // ================= أولاً: نظام التنقل الفوري بين الصفحات =================
    btnGoToRadio.addEventListener('click', () => { pageRadioList.style.display = 'block'; });
    btnBackToHome.addEventListener('click', () => { pageRadioList.style.display = 'none'; });
    btnBackToList.addEventListener('click', () => { pageRadioPlayer.style.display = 'none'; });

    // ================= ثانياً: جلب الإذاعات ديناميكياً بالـ API =================
    async function loadRadiosFromAPI() {
        try {
            const response = await fetch('https://mp3quran.net/api/v3/radios?language=ar');
            const data = await response.json();
            
            if (data && data.radios) {
                allStations = data.radios.map(station => ({
                    name: station.name,
                    url: station.url
                }));

                // جعل إذاعة القرآن الكريم من القاهرة تظهر أول واحدة دائماً للشياكة والسرعة
                allStations.sort((a, b) => {
                    if (a.name.includes("القاهرة")) return -1;
                    if (b.name.includes("القاهرة")) return 1;
                    return 0;
                });

                renderRadioCards(allStations);
            }
        } catch (error) {
            cardsContainer.innerHTML = '<div class="loading-text" style="color:#ef4444; grid-column:1/-1; text-align:center;">خطأ في تحميل الإذاعات، يرجى التحقق من الإنترنت.</div>';
        }
    }

    // بناء الكروت وتوزيعها
    function renderRadioCards(stations) {
        cardsContainer.innerHTML = '';
        stations.forEach((station) => {
            const card = document.createElement('div');
            card.className = 'radio-card';
            
            // تنظيف الاسم من التكرار اللفظي الزائد ليكون المظهر مرتباً
            const cleanName = station.name.replace(/إذاعة|قمة|بث|مباشر/gi, '').trim();
            card.innerHTML = `<span class="radio-card-name">${cleanName}</span>`;
            
            // عند النقر: الانتقال الفوري لصفحة المشغل وبدء البث
            card.addEventListener('click', () => {
                currentSelectedStation = station;
                pageRadioPlayer.style.display = 'block'; // فتح صفحة المشغل المستقلة
                initiateRadioPlayback(station);
            });

            cardsContainer.appendChild(card);
        });
    }

    // ================= ثالثاً: إدارة تشغيل الراديو والتأثيرات البصرية =================
    function initiateRadioPlayback(station) {
        radioAudio.pause();
        radioAudio.removeAttribute('src');
        radioAudio.load();

        radioAudio.src = station.url;
        const cleanName = station.name.replace(/إذاعة|قمة|بث|مباشر/gi, '').trim();
        
        fullPlayerTitle.textContent = cleanName;
        fullPlayerStatus.textContent = "جاري الاتصال بالبث المباشر...";
        btnFullToggle.textContent = '⏸';
        audioWaves.classList.remove('active'); // إيقاف حركة الموجات مؤقتاً لحين التحميل

        radioAudio.play().then(() => {
            fullPlayerStatus.textContent = "مستمع الآن ⚡";
            audioWaves.classList.add('active'); // تفعيل حركة موجات الصوت الاحترافية عند خروج الصوت
        }).catch(err => {
            fullPlayerStatus.textContent = "البث غير متاح حالياً من المصدر.";
            audioWaves.classList.remove('active');
        });
    }

    // زر التشغيل والإيقاف المؤقت داخل صفحة المشغل الكبرى
    btnFullToggle.addEventListener('click', () => {
        if (radioAudio.paused) {
            radioAudio.play();
            btnFullToggle.textContent = '⏸';
            audioWaves.classList.add('active');
            fullPlayerStatus.textContent = "مستمع الآن ⚡";
        } else {
            radioAudio.pause();
            btnFullToggle.textContent = '▶';
            audioWaves.classList.remove('active');
            fullPlayerStatus.textContent = "تم الإيقاف مؤقتاً";
        }
    });

    // ميزة البحث اللحظي اللطيف
    searchInput.addEventListener('input', (e) => {
        const query = e.target.value.toLowerCase().trim();
        const filtered = allStations.filter(st => st.name.toLowerCase().includes(query));
        renderRadioCards(filtered);
    });

    // بدء تشغيل الـ API تلقائياً
    loadRadiosFromAPI();
});










// =============================================
// الكيانات البرمجية لمؤقت البومودرو
// =============================================
// =============================================
// أزرار وإدارة فتح وإغلاق الشاشة
// =============================================
// التحكم في ظهور وإخفاء القسم
